// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };

function useComponent(props: Props) {
  const initialColumns = props.columns.length > 0 ? props.columns : [
    { id: 'todo', name: 'To Do' },
    { id: 'in-progress', name: 'In Progress' },
    { id: 'done', name: 'Done' },
  ];
  const normalizedColumns = initialColumns.map((column, index) => ({
    id: column.id || (index === 0 ? 'todo' : index === 1 ? 'in-progress' : 'done'),
    name: column.name || (index === 0 ? 'To Do' : index === 1 ? 'In Progress' : 'Done'),
  }));

  const [tasks, setTasks] = useState<Array<{ id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate: string }>>(() =>
    props.tasks.map((task, index) => ({
      id: task.id || `task-${index + 1}`,
      title: task.title || 'Untitled task',
      priority: task.priority || 'medium',
      assignee: task.assignee || '',
      column: task.column || normalizedColumns[0].id,
      dueDate: task.dueDate || '',
    }))
  );
  const [draftTitle, setDraftTitle] = useState('');
  const [draftPriority, setDraftPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [isAddingTask, setIsAddingTask] = useState(false);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [moveTargetByTaskId, setMoveTargetByTaskId] = useState<Record<string, string>>({});

  React.useEffect(() => {
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent<StreamTaskChanged>;
      const incoming = customEvent.detail?.task;
      if (!incoming || !incoming.id) return;
      setTasks((current) => {
        if (customEvent.detail?.action === 'delete') {
          return current.filter((task) => task.id !== incoming.id);
        }
        const normalizedIncoming: { id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate: string } = {
          id: incoming.id || `task-${current.length + 1}`,
          title: incoming.title || 'Untitled task',
          priority: incoming.priority || 'medium',
          assignee: incoming.assignee || '',
          column: incoming.column || normalizedColumns[0].id,
          dueDate: incoming.dueDate || '',
        };
        const existingIndex = current.findIndex((task) => task.id === incoming.id);
        if (existingIndex >= 0) {
          const next = current.slice();
          next[existingIndex] = { ...next[existingIndex], ...normalizedIncoming };
          return next;
        }
        return [...current, normalizedIncoming];
      });
    };
    window.addEventListener('ggui:agent-data', handler);
    return () => window.removeEventListener('ggui:agent-data', handler);
  }, [normalizedColumns]);

  const columnIds = normalizedColumns.map((column) => column.id);
  const completedColumnId = columnIds.find((id) => /done/i.test(id)) || columnIds[columnIds.length - 1];

  const mergedTasks = tasks;
  const tasksByColumn = normalizedColumns.reduce<Record<string, typeof mergedTasks>>((acc, column) => {
    acc[column.id] = mergedTasks.filter((task) => task.column === column.id);
    return acc;
  }, {});

  const totalTasks = mergedTasks.length;
  const completedCount = mergedTasks.filter((task) => task.column === completedColumnId).length;

  const taskUpdate = useCallback((payload: ActionTaskUpdatePayload) => {
    const globalWindow = typeof window !== 'undefined' ? window : undefined;
    if (!globalWindow) return;
    const detail = new CustomEvent<ActionTaskUpdatePayload>('ggui:taskUpdate', { detail: payload });
    globalWindow.dispatchEvent(detail);
  }, []);

  const moveTask = useCallback((taskId: string, columnId: string) => {
    setTasks((current) => current.map((task) => (task.id === taskId ? { ...task, column: columnId } : task)));
    taskUpdate({ action: 'move', taskId, data: { column: columnId } });
  }, [taskUpdate]);

  const createTask = useCallback(() => {
    if (!draftTitle.trim()) {
      return;
    }
    const nextTaskId = `task-${Date.now()}`;
    const nextTask = {
      id: nextTaskId,
      title: draftTitle.trim(),
      priority: draftPriority,
      assignee: '',
      column: normalizedColumns[0].id,
      dueDate: '',
    };
    setTasks((current) => [...current, nextTask]);
    taskUpdate({ action: 'create', taskId: nextTaskId, data: { column: nextTask.column } });
    setDraftTitle('');
    setDraftPriority('medium');
    setIsAddingTask(false);
  }, [draftPriority, draftTitle, normalizedColumns, taskUpdate]);

  const saveTaskTitle = useCallback((taskId: string) => {
    const nextTitle = editingTitle.trim();
    if (!nextTitle) {
      return;
    }
    const taskColumn = tasks.find((task) => task.id === taskId)?.column || normalizedColumns[0].id;
    setTasks((current) => current.map((task) => (task.id === taskId ? { ...task, title: nextTitle } : task)));
    taskUpdate({ action: 'edit', taskId, data: { column: taskColumn } });
    setEditingTaskId(null);
    setEditingTitle('');
  }, [editingTitle, normalizedColumns, tasks, taskUpdate]);

  const startEditingTask = useCallback((taskId: string, currentTitle: string) => {
    setEditingTaskId(taskId);
    setEditingTitle(currentTitle);
  }, []);

  const cancelEditingTask = useCallback(() => {
    setEditingTaskId(null);
    setEditingTitle('');
  }, []);

  const setMoveTarget = useCallback((taskId: string, columnId: string) => {
    setMoveTargetByTaskId((current) => ({ ...current, [taskId]: columnId }));
  }, []);

  const handleMoveSelection = useCallback((taskId: string, nextColumn: string) => {
    if (nextColumn) {
      moveTask(taskId, nextColumn);
    }
  }, [moveTask]);

  const taskById = mergedTasks.reduce<Record<string, (typeof mergedTasks)[number]>>((acc, task) => {
    acc[task.id] = task;
    return acc;
  }, {});

  return {
    taskUpdate,
    taskChanged: undefined,
    columns: normalizedColumns,
    tasks: mergedTasks,
    tasksByColumn,
    totalTasks,
    completedCount,
    draftTitle,
    setDraftTitle,
    draftPriority,
    setDraftPriority,
    isAddingTask,
    setIsAddingTask,
    editingTaskId,
    editingTitle,
    setEditingTitle,
    moveTargetByTaskId,
    setMoveTargetByTaskId,
    taskById,
    moveTask,
    createTask,
    saveTaskTitle,
    startEditingTask,
    cancelEditingTask,
    setMoveTarget,
    handleMoveSelection,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  const priorityColors: Record<'low' | 'medium' | 'high', string> = {
    low: 'var(--ggui-color-success-500, #16a34a)',
    medium: 'var(--ggui-color-warning-500, #d97706)',
    high: 'var(--ggui-color-error-500, #dc2626)',
  };

  return (
    <Container maxWidth="full" padding={24}>
      <Stack gap={24}>
        <Card padding={20} radius="lg" shadow="sm">
          <Stack gap={12}>
            <Row align="center" justify="between" wrap>
              <Heading level={2}>Task Board</Heading>
              <Badge variant="primary">{state.totalTasks} tasks</Badge>
            </Row>
            <Row align="center" justify="between" wrap>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Completed: {state.completedCount}
              </Text>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Real-time updates enabled
              </Text>
            </Row>
          </Stack>
        </Card>

        <Row gap={16} align="start" wrap>
          {state.columns.map((column) => {
            const columnTasks = state.tasksByColumn[column.id] || [];
            return (
              <Card key={column.id} padding={16} radius="lg" shadow="sm" border>
                <Stack gap={16}>
                  <Row align="center" justify="between">
                    <Heading level={4}>{column.name}</Heading>
                    <Badge variant="secondary">{columnTasks.length}</Badge>
                  </Row>

                  <Stack gap={12}>
                    {columnTasks.map((task) => {
                      const isEditing = state.editingTaskId === task.id;
                      const selectedMoveTarget = state.moveTargetByTaskId[task.id] || '';
                      return (
                        <Card key={task.id} padding={12} radius="md" shadow="none" border>
                          <Stack gap={12}>
                            <Row align="start" justify="between" gap={12} wrap>
                              <Box style={{ flex: 1, minWidth: 0 }}>
                                {isEditing ? (
                                  <Stack gap={8}>
                                    <Input
                                      label="Task title"
                                      value={state.editingTitle}
                                      onChange={state.setEditingTitle}
                                      size="sm"
                                    />
                                    <Row gap={8}>
                                      <Button size="sm" onClick={() => state.saveTaskTitle(task.id)}>Save</Button>
                                      <Button size="sm" variant="ghost" onClick={state.cancelEditingTask}>Cancel</Button>
                                    </Row>
                                  </Stack>
                                ) : (
                                  <Stack gap={4}>
                                    <Text
                                      is="div"
                                      as={Clickable}
                                      weight="semibold"
                                      onDoubleClick={() => state.startEditingTask(task.id, task.title)}
                                      style={{ cursor: 'text' }}
                                    >
                                      {task.title}
                                    </Text>
                                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Double-click or edit button to rename</Text>
                                  </Stack>
                                )}
                              </Box>
                              <Badge variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'success'}>
                                {task.priority}
                              </Badge>
                            </Row>

                            <Row align="center" gap={12} wrap>
                              <Avatar name={task.assignee || 'Unassigned'} size="sm" />
                              <Stack gap={2}>
                                <Text variant="bodySmall">{task.assignee || 'Unassigned'}</Text>
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                                  {task.dueDate ? `Due ${task.dueDate}` : 'No due date'}
                                </Text>
                              </Stack>
                            </Row>

                            <Stack gap={8}>
                              <Select
                                label="Move task"
                                value={selectedMoveTarget}
                                onChange={(value) => state.setMoveTarget(task.id, value)}
                                options={state.columns
                                  .filter((target) => target.id !== column.id)
                                  .map((target) => ({ value: target.id, label: target.name }))}
                                placeholder="Select column"
                                size="sm"
                              />
                              <Row gap={8} wrap>
                                <Button
                                  size="sm"
                                  variant="outline"
                                  onClick={() => state.handleMoveSelection(task.id, selectedMoveTarget)}
                                  disabled={!selectedMoveTarget}
                                >
                                  Move
                                </Button>
                                <Button size="sm" variant="ghost" onClick={() => state.startEditingTask(task.id, task.title)}>Edit</Button>
                              </Row>
                            </Stack>
                          </Stack>
                        </Card>
                      );
                    })}
                  </Stack>

                  {state.isAddingTask ? (
                    <Card padding={12} radius="md" shadow="none" border>
                      <Stack gap={12}>
                        <Input
                          label="New task title"
                          value={state.draftTitle}
                          onChange={state.setDraftTitle}
                          placeholder="Enter task title"
                          size="sm"
                        />
                        <Select
                          label="Priority"
                          value={state.draftPriority}
                          onChange={(value) => state.setDraftPriority(value as 'low' | 'medium' | 'high')}
                          options={[
                            { value: 'low', label: 'Low' }
                            { value: 'medium', label: 'Medium' }
                            { value: 'high', label: 'High' }
                          ]}
                          size="sm"
                        />
                        <Row gap={8}>
                          <Button size="sm" onClick={state.createTask}>Add</Button>
                          <Button size="sm" variant="ghost" onClick={() => state.setIsAddingTask(false)}>Cancel</Button>
                        </Row>
                      </Stack>
                    </Card>
                  ) : (
                    <Button variant="outline" fullWidth onClick={() => state.setIsAddingTask(true)}>Add Task</Button>
                  )}
                </Stack>
              </Card>
            );
          })}
        </Row>

        <Card padding={16} radius="lg" shadow="sm">
          <Row align="center" justify="between" gap={12} wrap>
            <Text variant="bodySmall">Total tasks: {state.totalTasks}</Text>
            <Text variant="bodySmall">Completed: {state.completedCount}</Text>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Priority colors: 
              <Text is="span" color={priorityColors.low}>low</Text>, 
              <Text is="span" color={priorityColors.medium}>medium</Text>, 
              <Text is="span" color={priorityColors.high}>high</Text>
            </Text>
          </Row>
        </Card>
      </Stack>
    </Container>
  );
